'use client';
import { useEffect, useRef } from 'react';

interface Props {
  lat: number;
  lng: number;
  onChange: (lat: number, lng: number) => void;
}

export default function MapPicker({ lat, lng, onChange }: Props) {
  const containerRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<unknown>(null);
  const markerRef = useRef<unknown>(null);

  useEffect(() => {
    if (!containerRef.current) return;
    let destroyed = false;

    import('leaflet/dist/leaflet.css').then(() =>
      import('leaflet').then((mod) => {
        if (destroyed || !containerRef.current) return;
        const L = mod.default ?? mod;

        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        delete (L.Icon.Default.prototype as any)._getIconUrl;
        L.Icon.Default.mergeOptions({
          iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
          iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',
          shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
        });

        const map = L.map(containerRef.current!, { center: [lat, lng], zoom: 15 });
        L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
          attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors',
          maxZoom: 19,
        }).addTo(map);

        const marker = L.marker([lat, lng], { draggable: true }).addTo(map);
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        marker.on('dragend', () => { const p = (marker as any).getLatLng(); onChange(p.lat, p.lng); });
        map.on('click', (e: { latlng: { lat: number; lng: number } }) => {
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          (marker as any).setLatLng([e.latlng.lat, e.latlng.lng]);
          onChange(e.latlng.lat, e.latlng.lng);
        });

        mapRef.current = map;
        markerRef.current = marker;
      })
    );

    return () => {
      destroyed = true;
      if (mapRef.current) {
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        (mapRef.current as any).remove();
        mapRef.current = null;
        markerRef.current = null;
      }
    };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Sync external lat/lng (e.g. from geocoding)
  useEffect(() => {
    if (!markerRef.current || !mapRef.current) return;
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (markerRef.current as any).setLatLng([lat, lng]);
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (mapRef.current as any).setView([lat, lng], 15);
  }, [lat, lng]);

  return (
    <div
      ref={containerRef}
      className="w-full rounded-xl border border-border overflow-hidden"
      style={{ height: 220 }}
      aria-label="Delivery location map"
    />
  );
}
